  'emergency_medicine', 'clinical_decision', 'gi', 'adult',
  'ACG Clinical Guideline: Management of Acute Pancreatitis (Tenner 2013); IAP/APA Evidence-Based Guidelines 2013', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
