select
  s.id, 'board', NULL, 'Hospital implements patient-centered medical home (PCMH) — primary care transformation', '[{"label":"A","text":"Traditional model"},{"label":"B","text":"Patient-Centered Medical Home (PCMH) Transformation: (1) **PCMH model** (NCQA): comprehensive + patient-centered + coordinated + accessible + committed to quality + safety; (2) **Joint Principles** (AAP, AAFP, ACP, AOA 2007): personal physician, physician-directed team, whole-person orientation, care coordination, quality + safety, enhanced access, payment reform; (3) **Core elements**: team-based care, population health management, chronic disease management, behavioral health integration, care coordination + transitions, patient + family engagement; (4) **Population health**: registries, panel management, proactive outreach, gaps in care; (5) **Same-day access** + after-hours; telemedicine; group visits; (6) **Care coordination**: across specialists, hospitals, community; care managers for high-risk; (7) **Behavioral health integration**: Collaborative Care Model (CoCM); (8) **Quality improvement**: PDSA cycles, measurement-based care, EHR optimization; (9) **Patient engagement**: portal, education, shared decision-making, advisory councils, surveys; (10) **Multidisciplinary team**: physicians + APPs + nurses + MAs + behavioral health + social work + dietitian + pharmacist + community health workers; (11) **Payment models**: PMPM + quality bonuses + shared savings (vs fee-for-service); (12) **Outcomes evidence**: improved quality + access + experience + lower costs + reduced hospitalizations + better chronic disease management; (13) **Equity**: SDOH integration; (14) **NCQA recognition** + certification; (15) **Modern**: ongoing evolution + technology integration + AI assistance"},{"label":"C","text":"Random"},{"label":"D","text":"No team"},{"label":"E","text":"Refuse"}]'::jsonb,
  'B', 'PCMH: comprehensive + patient-centered + team-based + coordinated primary care. Joint Principles + NCQA. Population health + chronic disease management + behavioral health integration. Quality improvement + payment reform. Improved outcomes. Modern: primary care transformation.', NULL,
  'easy', 'signs_symptoms', 'review',
  'family_medicine', 'ems_mgmt', 'signs_symptoms', 'adult',
  'NCQA PCMH; AAFP', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
