      and q.board_specialty = 'internal_medicine'
      and q.scenario = 'Resident เตรียมตอบ board: "กลไก coagulation cascade + thrombophilia (factor V Leiden, prothrombin G20210A, protein C/S, antithrombin, antiphospholipid)?"'
  );

