select
  s.id, 'board', NULL, 'Hospital wants to reduce maternal mortality + improve obstetric outcomes — implement Maternal Early Warning Systems', '[{"label":"A","text":"Single intervention"},{"label":"B","text":"Maternal Quality Improvement Program: (1) Maternal Early Warning Systems (MEWS) — track vital signs trigger response (BP > 160/110, RR > 30, HR > 130, SpO2 < 95%, oliguria, AMS) → rapid response team activation; (2) Standardized bundles (AIM — Alliance for Innovation on Maternal Health): hypertension bundle, hemorrhage bundle, VTE bundle, sepsis bundle, maternal mental health, peripartum racial/ethnic disparities, severe maternal morbidity review; (3) Hemorrhage bundle: risk assessment, recognition + response, hemorrhage cart, MTP, drills; (4) Hypertensive bundle: severe range BP management protocols, MgSO4 use, transfer criteria; (5) Multidisciplinary simulations + drills (shoulder dystocia, hemorrhage, eclampsia, cardiac arrest); (6) Severe maternal morbidity (SMM) review committees + root cause analysis; (7) Levels of maternal care designation (similar to trauma — Level I-IV); (8) Continuous improvement + audit; (9) Address social determinants + disparities (Black women 3-4× maternal mortality in US); (10) Family/support involvement; (11) Mental health screening + treatment; (12) Quality metrics: maternal mortality ratio, SMM rate, blood transfusion rate, NICU admission, c-section rate, breastfeeding initiation, postpartum visit attendance"},{"label":"C","text":"Single specialty manages"},{"label":"D","text":"No data collection"},{"label":"E","text":"Avoid drills"}]'::jsonb,
  'B', 'Maternal mortality reduction = system-level multidisciplinary effort. MEWS for early recognition. Bundles standardize evidence-based care. Drills + simulations improve readiness. SMM review identifies improvement opportunities. Levels of maternal care match risk to capability. AIM + ACOG + national initiatives. Address disparities. Maternal mortality preventable in majority of cases — system improvement saves lives.', NULL,
  'medium', 'obgyn', 'review',
  'ob_gyn', 'ems_mgmt', 'obgyn', 'adult',
  'Alliance for Innovation on Maternal Health (AIM); ACOG Obstetric Care Consensus on Levels of Maternal Care 2019', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'obg_ems_mgmt'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
      and q.board_specialty = 'ob_gyn'
      and q.scenario = 'Hospital wants to reduce maternal mortality + improve obstetric outcomes — implement Maternal Early Warning Systems'
