select
  s.id, 'board', NULL, 'Hospital implements ERAS protocol for elective C-section — Enhanced Recovery After Cesarean (ERAC)', '[{"label":"A","text":"Traditional restrictive recovery"},{"label":"B","text":"Enhanced Recovery After Cesarean (ERAC) — multimodal evidence-based: (1) Pre-op: counseling, no prolonged fasting (clear fluids until 2h, carb loading 2h pre-op), antibiotic prophylaxis 60 min pre-op (cefazolin + azithromycin), VTE prophylaxis (mechanical + LMWH start 6-12h post-op), normothermia, chlorhexidine skin prep; (2) Intra-op: neuraxial anesthesia preferred (spinal/CSE), multimodal analgesia (intrathecal morphine + IV acetaminophen + NSAID), minimize opioid use, restrictive IV fluid, blunt expansion of uterine incision (less blood loss), uterotonic at delivery (oxytocin); (3) Post-op: early oral diet (within 1h), early ambulation (within 6h), Foley removal 12h, opioid-sparing analgesia (acetaminophen + NSAID + TAP block + low-dose opioid PRN), thromboprophylaxis continued, breastfeeding support, mental health screening; (4) Discharge planning early; (5) Outcomes: reduced LOS (1-2 days), opioid use ↓ 50%, complications ↓, breastfeeding rates ↑, patient satisfaction ↑; (6) SOGC + ERAS Society + Cooper Medical Center publications; (7) Implementation requires multidisciplinary team + audit + continuous improvement"},{"label":"C","text":"Bed rest 5 days"},{"label":"D","text":"Opioid-only analgesia"},{"label":"E","text":"Restrict fluid intake"}]'::jsonb,
  'B', 'ERAC = ERAS principles applied to cesarean. Evidence: shorter LOS, less opioid use, better breastfeeding, less morbidity, higher satisfaction. Multimodal pain management (intrathecal morphine + NSAID + acetaminophen + TAP block + minimal opioid) — opioid-sparing reduces side effects + neonatal exposure (in breastfeeding). Early diet + ambulation + Foley removal. Counseling + family-centered care. Quality improvement driven.', NULL,
  'medium', 'obgyn', 'review',
  'ob_gyn', 'ems_mgmt', 'obgyn', 'adult',
  'ERAS Society Guidelines for Cesarean Delivery 2018-2019; Wilson RD et al. Am J Obstet Gynecol 2018', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'obg_ems_mgmt'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
      and q.board_specialty = 'ob_gyn'
