select
  s.id, 'board', NULL, 'ชายไทยอายุ 78 ปี underlying HT, mild dementia ตกจากบันได 3 ขั้น มาห้องฉุกเฉินด้วยปวด left hip + ไม่สามารถ weight bear ได้

V/S: BP 138/82, HR 96, RR 18, Temp 36.8°C
PE: shortening + external rotation ของ left leg, tender at left hip, no neurovascular deficit

X-ray hip: displaced intracapsular femoral neck fracture left + Garden III', '[{"label":"A","text":"Non-operative + bedrest 6 weeks"},{"label":"B","text":"Displaced Intracapsular Femoral Neck Fracture (Garden III-IV) in elderly: high risk avascular necrosis (AVN) + nonunion (intracapsular blood supply tenuous) — surgical management within 24-48 hours (Cochrane evidence — earlier surgery lower mortality): hemiarthroplasty (if low demand, > 80, comorbidity) or total hip arthroplasty (THA — if active independent ambulator, < 75-80, better functional outcome long-term — HEALTH trial NEJM 2019); avoid internal fixation in elderly with displaced fracture (high AVN/nonunion); pre-op: optimize comorbidities, manage delirium (CAM), DVT prophylaxis, pain control (multimodal — avoid opioid-only, regional block — fascia iliaca compartment block), nutrition, geriatric consult; multidisciplinary care (ortho-geriatric co-management — Cochrane evidence reduces mortality + LOS); post-op: early mobilization, rehabilitation, fall prevention, osteoporosis screening + treatment (DEXA, bisphosphonate, vit D)"},{"label":"C","text":"Bracing only"},{"label":"D","text":"Amputation"},{"label":"E","text":"Discharge home with NSAIDs"}]'::jsonb,
  'B', 'Hip fracture in elderly: mortality 20-30% first year. Intracapsular displaced (Garden III-IV) — arthroplasty preferred over fixation due to high AVN risk. THA vs hemi: THA for active independent < 75-80; hemi for low-demand elderly. Early surgery < 48h reduces mortality (NICE, AAOS). Ortho-geriatric co-management improves outcomes. Multidisciplinary care + secondary prevention (osteoporosis Rx, fall prevention) essential.', NULL,
  'easy', 'trauma', 'review',
  'orthopedics', 'clinical_decision', 'trauma', 'adult',
  'AAOS Clinical Practice Guideline: Hip Fractures 2014; HEALTH Trial NEJM 2019; NICE Hip Fracture Guideline 2017', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'ortho_clinical_decision'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
      and q.board_specialty = 'orthopedics'
      and q.scenario = 'ชายไทยอายุ 78 ปี underlying HT, mild dementia ตกจากบันได 3 ขั้น มาห้องฉุกเฉินด้วยปวด left hip + ไม่สามารถ weight bear ได้

V/S: BP 138/82, HR 96, RR 18, Temp 36.8°C
PE: shortening + external rotation ของ left leg, tender at left hip, no neurovascular deficit

X-ray hip: displaced intracapsular femoral neck fracture left + Garden III'
  );

