select
  s.id, 'board', NULL, 'อาจารย์อธิบาย physiology — muscle + tendon biology + healing', '[{"label":"A","text":"No biology relevant"},{"label":"B","text":"Muscle + Tendon Biology: (1) **Muscle types**: skeletal (voluntary, striated), cardiac, smooth; **fiber types** (skeletal): Type I slow-twitch oxidative (endurance, fatigue-resistant, mitochondria-rich, red), Type IIa fast-twitch oxidative-glycolytic (mixed), Type IIb fast-twitch glycolytic (power, fatigue-easily); training-dependent shift; (2) **Muscle contraction**: actin-myosin sliding filament theory — ATP-dependent — neural input → ACh release → Ca release from SR → cross-bridge cycling; (3) **Muscle injury**: strain (overstretch — pain, bleeding) → hematoma → inflammatory phase → satellite cell activation → regeneration with new myofibers; scar tissue if extensive; (4) **Healing phases**: hemostasis + inflammation → cell proliferation → matrix remodeling; (5) **Tendon biology**: type I collagen primarily; lower vascularity → slower healing; tendon healing phases similar — inflammation, proliferation, remodeling; (6) **Risk factors** for tendinopathy: overuse, age, diabetes, fluoroquinolones (CI), genetics; (7) **Treatment principles**: relative rest (not absolute — controlled loading promotes healing), eccentric loading (Alfredson protocol for Achilles), NSAIDs short-term, modalities, PT; surgical repair for complete rupture; (8) **Sports medicine principles**: prehabilitation, biomechanics, return to sport criteria, prevention programs (FIFA 11+, ACL injury prevention); (9) **PRP (platelet-rich plasma)**: emerging therapy for tendinopathy + selected injuries — mixed evidence; (10) **Eccentric exercise**: gold standard for chronic tendinopathy (Alfredson protocol)"},{"label":"C","text":"All muscle same"},{"label":"D","text":"No healing process"},{"label":"E","text":"Cardiac and skeletal same"}]'::jsonb,
  'B', 'Muscle + tendon biology critical for sports medicine + orthopedic care. Fiber types + training. Injury + healing phases. Tendinopathy chronic — eccentric loading evidence-based (Alfredson). Fluoroquinolones cause tendon rupture (avoid). Modern treatments: controlled loading, PT, biologics (PRP). Prevention programs reduce injury (FIFA 11+).', NULL,
  'easy', 'msk_nontrauma', 'review',
  'orthopedics', 'basic_science', 'msk_nontrauma', 'adult',
  'AAOS OKU Sports Medicine; Alfredson H Sports Med 1998', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'ortho_basic_science'
  and s.audience = 'board'
