select
  s.id, 'board', NULL, 'Surgeon ออกข้อสอบเรื่อง surgical infection + antibiotic prophylaxis อาจารย์อธิบาย wound classification + recommendations', '[{"label":"A","text":"All surgeries need same prophylaxis"},{"label":"B","text":"**Wound classification** (CDC): (1) **Clean**: no inflammation, no entry into GI/GU/respiratory tract — SSI 1-2% — e.g., hernia, breast (prophylaxis typically not needed unless prosthesis/foreign body); (2) **Clean-contaminated**: GI/GU/respiratory entered under controlled conditions — SSI 5-10% — e.g., elective colectomy, cholecystectomy — single pre-op antibiotic dose; (3) **Contaminated**: gross spillage, fresh trauma, acute inflammation — SSI 15-20% — therapeutic antibiotic 24h; (4) **Dirty/Infected**: pus, perforated viscus, devitalized tissue — SSI > 30% — therapeutic antibiotic full course. **Prophylaxis principles**: appropriate agent (typically 1st-gen cephalosporin for skin flora; add metronidazole for colorectal), within 60 min before incision (within 120 min for vancomycin/fluoroquinolone), re-dose for long procedures (3-4h), single dose for most, discontinue within 24h post-op (NSQIP)"},{"label":"C","text":"Antibiotics for 7 days for all surgeries"},{"label":"D","text":"No antibiotics ever needed"},{"label":"E","text":"Topical antibiotics only"}]'::jsonb,
  'B', 'Surgical wound classification CDC + ACS NSQIP guides antibiotic prophylaxis + SSI prevention. Key principles: (1) appropriate drug (skin flora for most; gut flora for colorectal); (2) timing within 60 min of incision (correct timing strongest predictor); (3) adequate dose (weight-based for obese); (4) redosing for prolonged surgery; (5) discontinue ≤ 24h (longer = no benefit + resistance). Other SSI prevention: glycemic control, normothermia, chlorhexidine skin prep, smoking cessation, no shaving (clipping), oxygen optimization. Bundle approach (Centre Comprehensive Unit Safety) reduces SSI.', NULL,
  'medium', 'id', 'review',
  'surgery', 'basic_science', 'id', 'adult',
  'CDC Guideline for the Prevention of Surgical Site Infection 2017; ACS NSQIP Surgical Care Improvement Project; Bratzler DW et al. CID 2013', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'surg_basic_science'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
      and q.board_specialty = 'surgery'
      and q.scenario = 'Surgeon ออกข้อสอบเรื่อง surgical infection + antibiotic prophylaxis อาจารย์อธิบาย wound classification + recommendations'
  );

